#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_NODES 10000

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*)malloc(sizeof(TreeNode));
    newNode->val = val;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

// Function to deserialize the binary tree from the given level-order traversal
TreeNode* deserialize(int* arr, int n) {
    if (n == 0 || arr[0] == -1) return NULL;

    TreeNode* root = createTreeNode(arr[0]);
    TreeNode** queue = (TreeNode**)malloc(sizeof(TreeNode*) * n);
    int front = 0, rear = 0;
    queue[rear++] = root;

    int i = 1;
    while (front < rear && i < n) {
        TreeNode* node = queue[front++];

        // Left child
        if (i < n && arr[i] != -1) {
            node->left = createTreeNode(arr[i]);
            queue[rear++] = node->left;
        }
        i++;

        // Right child
        if (i < n && arr[i] != -1) {
            node->right = createTreeNode(arr[i]);
            queue[rear++] = node->right;
        }
        i++;
    }

    free(queue);
    return root;
}

// Function to serialize the binary tree into a level-order traversal
int* serialize(TreeNode* root, int* outSize) {
    if (!root) {
        *outSize = 0;
        return NULL;
    }

    int* result = (int*)malloc(sizeof(int) * MAX_NODES);
    TreeNode** queue = (TreeNode**)malloc(sizeof(TreeNode*) * MAX_NODES);
    int front = 0, rear = 0, idx = 0;
    queue[rear++] = root;

    while (front < rear) {
        TreeNode* node = queue[front++];

        if (node) {
            result[idx++] = node->val;
            queue[rear++] = node->left;
            queue[rear++] = node->right;
        } else {
            result[idx++] = -1;
        }
    }

    // Remove trailing -1 values
    while (idx > 0 && result[idx - 1] == -1) {
        idx--;
    }

    *outSize = idx;
    free(queue);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int n;
        scanf("%d", &n);

        int* arr = (int*)malloc(sizeof(int) * n);
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }

        TreeNode* root = deserialize(arr, n);
        int outSize;
        int* result = serialize(root, &outSize);

        for (int i = 0; i < outSize; i++) {
            printf("%d ", result[i]);
        }
        printf("\n");

        free(arr);
        free(result);
    }

    return 0;
}

