import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    // Define the structure for a tree node
    static class TreeNode {
        int val;
        TreeNode left;
        TreeNode right;
        TreeNode(int x) { val = x; }
    }

    // Function to deserialize the binary tree from the given level-order traversal
    public static TreeNode deserialize(int[] arr) {
        int n = arr.length;
        if (n == 0 || arr[0] == -1) return null;

        TreeNode root = new TreeNode(arr[0]);
        Queue<TreeNode> q = new LinkedList<>();
        q.offer(root);

        int i = 1;
        while (!q.isEmpty() && i < n) {
            TreeNode node = q.poll();

            // Left child
            if (i < n && arr[i] != -1) {
                node.left = new TreeNode(arr[i]);
                q.offer(node.left);
            }
            i++;

            // Right child
            if (i < n && arr[i] != -1) {
                node.right = new TreeNode(arr[i]);
                q.offer(node.right);
            }
            i++;
        }

        return root;
    }

    // Function to serialize the binary tree into a level-order traversal
    public static int[] serialize(TreeNode root) {
        if (root == null) return new int[0];

        Queue<TreeNode> q = new LinkedList<>();
        q.offer(root);
        StringBuilder sb = new StringBuilder();

        while (!q.isEmpty()) {
            TreeNode node = q.poll();

            if (node != null) {
                sb.append(node.val).append(" ");
                q.offer(node.left);
                q.offer(node.right);
            } else {
                sb.append("-1 ");
            }
        }

        // Remove trailing -1 values
        String[] tokens = sb.toString().trim().split(" ");
        int[] result = new int[tokens.length];
        for (int i = 0; i < tokens.length; i++) {
            result[i] = Integer.parseInt(tokens[i]);
        }

        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();

        while (T-- > 0) {
            int n = sc.nextInt();

            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }

            TreeNode root = deserialize(arr);
            int[] result = serialize(root);

            for (int i = 0; i < result.length; i++) {
                System.out.print(result[i] + " ");
            }
            System.out.println();
        }
    }
}

